const emit = () => {
    const baseRelays = normalize(context.get('baseRelays') || {
        "闁插洭顥LY": false,
        "閸旂姵鏋LY": false,
        "濞撳懏鏋LY": false,
        "婢跺秳缍匯LY": false,
        "濞撳懘娴俁LY": false,
        "Feeding_led": true,
        "Adding_led": false,
        "Clearing_led": false
    });
    baseRelays["濞撳懘娴俁LY"] = !!context.get('zeroPulseActive');
    return {
        topic: "relay_state",
        station_num: context.get('station_num') || stationNum,
        relays: baseRelays,
        payload: baseRelays
    };
};

if (msg.relays && typeof msg.relays === 'object') {
    const baseRelays = normalize(msg.relays);
    baseRelays["濞撳懘娴俁LY"] = false;
    context.set('baseRelays', baseRelays);
    return emit();
}

