    const activeTimer = context.get('zeroPulseTimer');
    if (activeTimer) clearTimeout(activeTimer);

    context.set('zeroPulseActive', true);
    const outMsg = emit();

    const timer = setTimeout(() => {
        context.set('zeroPulseActive', false);
        context.set('zeroPulseTimer', null);
        node.send(emit());
    }, ZERO_MS);

    context.set('zeroPulseTimer', timer);
    return outMsg;
}

