const RUNTIME_KEY = 'feed_runtime_v1';
const SAVE_INTERVAL_MS = 5000;
const MAX_SESSION_MS = 30 * 60 * 1000; // 30閸掑棝鎸撻敍宀冪Т鏉╁洩顫嬫稉楦款啎婢跺洭鏆遍弮鍫曟？閸嬫粎鏁nconst now = Date.now();
const topic = msg.topic || '';

// === 1. 娑撳﹣绗呴弬鍥︾瑢閸欐﹢鍣洪崚婵嗩潗閸栨牭绱欓崘鍛摠閹緤绱?===
let regWeight = context.get('regWeight') ?? 0.0;
let regSensor = context.get('regSensor') ?? false;
let cow_eid = context.get('cow_eid') ?? '';
let cow_vid = context.get('cow_vid') ?? '';
let pic_url = context.get('pic_url') ?? '';

let regMode = context.get('regMode') ?? 'FEEDING';
let stableMode = context.get('stableMode') ?? context.get('stableMode', 'file') ?? 'FEEDING';
let stableTs = context.get('stableTs') ?? context.get('stableTs', 'file') ?? 0;

let state = context.get('state') ?? 'IDLE';
let startWeight = context.get('startWeight') ?? 0.0;
let startTime = context.get('startTime') ?? now;
let lastPersistTs = context.get('lastPersistTs') ?? 0;
let feedCount = context.get('feedCount') ?? 0;

let outputRecord = null;
let isRelevantUpdate = false;
let forcePersist = false;

// === 2. 閸愬嘲鎯庨崝銊ょ濞嗏剝鈧勪划婢跺稄绱欓弬鍥︽閹緤绱?===
if (context.get('bootLoaded') !== true) {
    const saved = context.get(RUNTIME_KEY, 'file');
    if (saved && typeof saved === 'object') {
        regWeight = Number(saved.regWeight ?? regWeight);
        regSensor = !!saved.regSensor;
        cow_eid = String(saved.cow_eid ?? cow_eid);
        cow_vid = String(saved.cow_vid ?? cow_vid);
        pic_url = String(saved.pic_url ?? pic_url);
        regMode = String(saved.regMode ?? regMode);
        stableMode = String(saved.stableMode ?? stableMode);
        stableTs = Number(saved.stableTs ?? stableTs);
        state = String(saved.state ?? state);
        startWeight = Number(saved.startWeight ?? startWeight);
        startTime = Number(saved.startTime ?? startTime);
        feedCount = Number(saved.feedCount ?? feedCount);

        // 鐡掑懏妞傞崚銈呯暰閿涙碍浠径宥囨畱 session 瀹歌尪绉存潻鍥ㄦ付婢堆冨帒鐠佸憡妞傞梹鍖＄礉閻╁瓨甯存稉銏犵磾
        if ((now - startTime) > MAX_SESSION_MS) {
            node.warn(`閸愬嘲鎯庨崝銊︿划婢跺稄绱皊ession 瀹歌尪绉撮弮?${((now - startTime) / 1000 / 60).toFixed(1)} 閸掑棝鎸撻敍灞兼丢瀵啯妫?session`);
            state = 'IDLE';
            cow_eid = '';
            cow_vid = '';
            pic_url = '';
            startWeight = regWeight;
            startTime = now;
        }
    }
    context.set('bootLoaded', true);
}

function persistRuntime(force) {
    const ts = Date.now();
    if (!force && (ts - lastPersistTs < SAVE_INTERVAL_MS)) return;

    const runtime = {
        regWeight,
        regSensor,
        cow_eid,
        cow_vid,
        pic_url,
        regMode,
        stableMode,
        stableTs,
        state,
        startWeight,
        startTime,
        feedCount,
        savedAt: ts
    };

    context.set(RUNTIME_KEY, runtime, 'file');
    context.set('lastPersistTs', ts);
    lastPersistTs = ts;
}

// 鐡掑懏妞傞崚銈呯暰鏉堝懎濮崙鑺ユ殶閿涙ession 閺冨爼鏆遍弰顖氭儊鐡掑懓绻冩稉濠囨
function isSessionExpired(durMs) {
